import{c as t,Q as a,j as s,m as r}from"./chunks/framework.BPKcPtvA.js";const u=JSON.parse('{"title":"Checkout — URL fragment key","description":"Why the AES-256-GCM key lives in the URL fragment and what it protects.","frontmatter":{"title":"Checkout — URL fragment key","description":"Why the AES-256-GCM key lives in the URL fragment and what it protects."},"headers":[],"relativePath":"checkout/fragment-key.md","filePath":"checkout/fragment-key.md","lastUpdated":1778951051000}'),o={name:"checkout/fragment-key.md"};function n(i,e,h,l,c,p){return a(),s("div",null,[...e[0]||(e[0]=[r(`<h1 id="url-fragment-key-privacy" tabindex="-1">URL fragment key (privacy) <a class="header-anchor" href="#url-fragment-key-privacy" aria-label="Permalink to &quot;URL fragment key (privacy)&quot;">​</a></h1><p>The MuHaven hosted checkout URL splits into two parts:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://muhaven.app/pay/c/01HMTV9X.../#k=AbCdEfGhIjKlMnOpQrStUvWxYz123456</span></span>
<span class="line"><span>^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^   ^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^^</span></span>
<span class="line"><span>              path (server-visible)                fragment (client-only)</span></span></code></pre></div><p>The <strong>fragment</strong> (everything after <code>#</code>) is a base64url-encoded 32-byte AES-256-GCM key. The server stores the <strong>ciphertext</strong> of the session payload; the fragment key decrypts it client-side.</p><p>This page explains the security property, what attacks it prevents, and what the limits are.</p><h2 id="the-property" tabindex="-1">The property <a class="header-anchor" href="#the-property" aria-label="Permalink to &quot;The property&quot;">​</a></h2><blockquote><p><strong>The MuHaven backend cannot decrypt a checkout session payload, even if it wanted to.</strong></p></blockquote><p>The session row in <code>checkout_sessions</code> stores:</p><ul><li><code>id</code> (the ULID after <code>/pay/c/</code>)</li><li><code>enc_payload</code> (AES-256-GCM ciphertext + IV + tag)</li><li>Public metadata (issuer ID, status, created/expires timestamps, webhook URL)</li></ul><p>The session row does <strong>not</strong> store the AES-256-GCM key. The key lives only:</p><ol><li>In the URL fragment (the issuer&#39;s browser when they minted it, the buyer&#39;s browser when they opened it).</li><li>In any side-channel where the link was shared (Telegram messages, email, etc.).</li></ol><h2 id="what-s-in-the-encrypted-payload" tabindex="-1">What&#39;s in the encrypted payload <a class="header-anchor" href="#what-s-in-the-encrypted-payload" aria-label="Permalink to &quot;What&#39;s in the encrypted payload&quot;">​</a></h2><p>Cleartext fields, encrypted at session-create time:</p><ul><li>Token symbol + contract address</li><li>Amount in mhUSDC (6-decimal)</li><li>Issuer label (&quot;Treasury Issuer (Verified)&quot;)</li><li>Optional buyer-bound label</li></ul><p>What&#39;s <strong>not</strong> in the payload (these are public/server-visible):</p><ul><li>The session ID (it&#39;s in the path).</li><li>The issuer&#39;s user ID (server-side row).</li><li>The expires-at timestamp (server-side row).</li><li>The webhook URL (server-side row; the secret is hashed at rest).</li><li>The status (server-side row, updated on settlement).</li></ul><p>The split is intentional: the operator needs visibility into &quot;which sessions are paying webhooks, which have expired, when to cancel old sessions&quot; — but they don&#39;t need the cleartext amount or token to do that.</p><h2 id="why-url-fragments-specifically" tabindex="-1">Why URL fragments specifically? <a class="header-anchor" href="#why-url-fragments-specifically" aria-label="Permalink to &quot;Why URL fragments specifically?&quot;">​</a></h2><p>Three properties of the URL fragment (<code>#...</code>) per the HTTP / browser spec:</p><ol><li><strong>Fragments are not sent in <code>Referer</code> headers.</strong> When the buyer navigates from the checkout page to (say) an Arbiscan link in the success screen, the <code>Referer</code> header carries the full URL <em>up to but not including</em> the <code>#</code>. Arbiscan doesn&#39;t learn the key.</li><li><strong>Fragments are not logged by web servers.</strong> Apache, Nginx, Cloudflare, your reverse proxy — none of them see the fragment. The server only ever sees the path.</li><li><strong>Fragments stay in the address bar.</strong> They&#39;re visible to the user, can be copied / shared / forwarded — but they aren&#39;t transmitted unless the user explicitly shares the URL.</li></ol><p>This isn&#39;t a MuHaven invention — it&#39;s the Stripe Checkout pattern, the BitWarden share pattern, the standard browser-side capability scheme. We&#39;re applying it to a privacy-preserving payment surface.</p><h2 id="attacks-this-prevents" tabindex="-1">Attacks this prevents <a class="header-anchor" href="#attacks-this-prevents" aria-label="Permalink to &quot;Attacks this prevents&quot;">​</a></h2><h3 id="operator-decides-to-peek-at-all-payment-amounts" tabindex="-1">&quot;Operator decides to peek at all payment amounts&quot; <a class="header-anchor" href="#operator-decides-to-peek-at-all-payment-amounts" aria-label="Permalink to &quot;&quot;Operator decides to peek at all payment amounts&quot;&quot;">​</a></h3><p>The operator literally cannot. They have ciphertext + IV + tag; without the key, breaking AES-256-GCM is computationally infeasible.</p><p>If the operator wanted to learn the amounts, they&#39;d need to:</p><ol><li>Run a SQL query against <code>checkout_sessions</code> → returns only ciphertext.</li><li>Cross-correlate with on-chain <code>Subscription.purchase</code> events at settlement time → learns the <strong>public buyer-wallet ↔ on-chain encrypted-handle</strong> mapping.</li></ol><p>The cleartext amount at the moment of purchase is recoverable only if the operator also runs a MITM against the buyer&#39;s browser session, which is detectable (TLS pinning + reasonable CSP) and outside the threat model.</p><h3 id="operator-s-db-gets-stolen" tabindex="-1">&quot;Operator&#39;s DB gets stolen&quot; <a class="header-anchor" href="#operator-s-db-gets-stolen" aria-label="Permalink to &quot;&quot;Operator&#39;s DB gets stolen&quot;&quot;">​</a></h3><p>The attacker has ciphertext rows. They don&#39;t have the keys. They learn:</p><ul><li>Aggregate payment counts.</li><li>Per-issuer payment counts.</li><li>Webhook URLs (not the secrets — those are HMACed at rest).</li><li>Session status.</li></ul><p>They don&#39;t learn:</p><ul><li>Per-session amounts.</li><li>Per-session token symbols.</li><li>Per-session issuer labels (only the issuer ID, not the human-readable label which is in the payload).</li></ul><h3 id="insider-screenshots-a-checkout-url-from-a-logged-telegram-message" tabindex="-1">&quot;Insider screenshots a checkout URL from a logged Telegram message&quot; <a class="header-anchor" href="#insider-screenshots-a-checkout-url-from-a-logged-telegram-message" aria-label="Permalink to &quot;&quot;Insider screenshots a checkout URL from a logged Telegram message&quot;&quot;">​</a></h3><p>The screenshot includes the fragment, so the insider gets the key. They could decrypt the payload and open the checkout page. But:</p><ul><li>They&#39;d then need to pay with their own wallet (the MuHaven wallet that signs is <em>theirs</em>, not the original buyer&#39;s).</li><li>The audit log would clearly record their wallet as the payer.</li><li>The original issuer notification + webhook would say &quot;buyer 0x[insider] paid&quot;, not the intended buyer.</li></ul><p>The fragment-key scheme doesn&#39;t make checkout URLs &quot;secret&quot; — it makes them <strong>bearer capabilities</strong>. Treat them like passwords: don&#39;t paste them into channels you don&#39;t trust.</p><h2 id="what-the-fragment-key-scheme-doesn-t-prevent" tabindex="-1">What the fragment-key scheme doesn&#39;t prevent <a class="header-anchor" href="#what-the-fragment-key-scheme-doesn-t-prevent" aria-label="Permalink to &quot;What the fragment-key scheme doesn&#39;t prevent&quot;">​</a></h2><p>It&#39;s important to be precise. The scheme does <strong>not</strong> prevent:</p><ul><li><strong>A buyer&#39;s browser extension reading the URL.</strong> The buyer&#39;s browser sees the fragment. Don&#39;t paste your own checkout URL into a browser session with an untrusted extension installed.</li><li><strong>Sharing the URL to the wrong party.</strong> Like any bearer capability, anyone with the URL can pay. If you accidentally share to a public channel, cancel the checkout immediately.</li><li><strong>Buyer-side malware.</strong> If the buyer&#39;s machine is compromised, the attacker reads the fragment + the buyer&#39;s passkey. This is the threat model floor for any browser-based payment.</li><li><strong>Operator logs the entire <code>window.location</code> via injected JS.</strong> The checkout page&#39;s CSP locks scripts to <code>self</code> precisely to make this hard. If the operator wanted to inject a key-exfil script, they&#39;d have to break their own CSP claims first — which would be detectable via subresource integrity in the page source.</li></ul><h2 id="sharing-checkout-urls-safely" tabindex="-1">Sharing checkout URLs safely <a class="header-anchor" href="#sharing-checkout-urls-safely" aria-label="Permalink to &quot;Sharing checkout URLs safely&quot;">​</a></h2><p>✅ <strong>DO:</strong></p><ul><li>Share via end-to-end encrypted channels (Signal, iMessage, Telegram secret chats, ProtonMail).</li><li>Share as plain text (preserves fragment) over markdown-link surfaces that don&#39;t strip fragments.</li><li>Cancel checkouts you didn&#39;t share to the intended buyer.</li></ul><p>❌ <strong>DON&#39;T:</strong></p><ul><li>Post in a public channel.</li><li>Email through a corporate proxy that strips fragments (some EAS / Mimecast configs do this).</li><li>Convert to a short URL (most shorteners strip fragments).</li><li>Paste into a &quot;click-track&quot; tool that wraps the URL.</li></ul><p>If the buyer reports a &quot;Session not found&quot; error, the most common cause is fragment loss in transit. Re-share the link in a different channel.</p><h2 id="where-next" tabindex="-1">Where next <a class="header-anchor" href="#where-next" aria-label="Permalink to &quot;Where next&quot;">​</a></h2><ul><li><a href="/checkout/for-issuers">For issuers</a> — how the URL gets minted.</li><li><a href="/checkout/for-buyers">For buyers</a> — what the buyer experiences.</li><li><a href="/checkout/webhooks">Webhooks &amp; receipts</a> — server-to-server settlement notifications.</li></ul>`,47)])])}const y=t(o,[["render",n]]);export{u as __pageData,y as default};
